// Converte caracteres especiais do português para equivalentes ASCII
// para compatibilidade com impressoras Zebra que não suportam UTF-8
function normalizarTexto(str) {
  if (!str) return str;
  return str
    .replace(/[àáâãä]/g, 'a')
    .replace(/[ÀÁÂÃÄ]/g, 'A')
    .replace(/[èéêë]/g, 'e')
    .replace(/[ÈÉÊË]/g, 'E')
    .replace(/[ìíîï]/g, 'i')
    .replace(/[ÌÍÎÏ]/g, 'I')
    .replace(/[òóôõö]/g, 'o')
    .replace(/[ÒÓÔÕÖ]/g, 'O')
    .replace(/[ùúûü]/g, 'u')
    .replace(/[ÙÚÛÜ]/g, 'U')
    .replace(/[ç]/g, 'c')
    .replace(/[Ç]/g, 'C')
    .replace(/[ñ]/g, 'n')
    .replace(/[Ñ]/g, 'N')
    .replace(/[ý]/g, 'y')
    .replace(/[Ý]/g, 'Y');
}

